insert into species (owner_user_id, source_id, visibility, slug, name, summary, description, size, base_speed, languages, subspecies_slugs, mechanics, is_system_content)
values
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'elfo', 'Elfo', 'Especie agil y perceptiva, asociada con sentidos agudos y entrenamiento natural.', 'Seed inicial para validar el eje species-subspecies del catalogo. La modelizacion completa de rasgos puede ampliarse mas adelante.', 'medium', 30, array['comun', 'elfico']::text[], array['high-elf', 'wood-elf']::text[], '[{"type":"ability_bonus","ability":"dexterity","value":2},{"type":"speed","value":30},{"type":"darkvision","range":60},{"type":"language","mode":"fixed","language":"comun"},{"type":"language","mode":"fixed","language":"elfico"},{"type":"proficiency","proficiencyType":"skill","value":"perception"},{"type":"note","text":"Advantage on saving throws against being charmed, and magic cannot put you to sleep."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'humano', 'Humano', 'Versatil y adaptable, con mejoras generales de caracteristica.', 'Seed inicial basada en la documentacion SRD del proyecto. Conviene revisar nombres y redaccion final contra la fuente oficial antes de ampliar el catalogo.', 'medium', 30, array['comun', 'choose:any:1']::text[], '{}'::text[], '[{"type":"ability_bonus","ability":"strength","value":1},{"type":"ability_bonus","ability":"dexterity","value":1},{"type":"ability_bonus","ability":"constitution","value":1},{"type":"ability_bonus","ability":"intelligence","value":1},{"type":"ability_bonus","ability":"wisdom","value":1},{"type":"ability_bonus","ability":"charisma","value":1},{"type":"speed","value":30},{"type":"language","mode":"fixed","language":"comun"},{"type":"choose_language","count":1}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'enano', 'Enano', 'Especie resistente y disciplinada, asociada con fortaleza, tradicion y sentidos agudos bajo tierra.', 'Entrada canonica ampliada para reforzar la cobertura del creador guiado con una especie robusta del SRD.', 'medium', 25, array['comun', 'dwarfico']::text[], array['hill-dwarf', 'mountain-dwarf']::text[], '[{"type":"ability_bonus","ability":"constitution","value":2},{"type":"speed","value":25},{"type":"darkvision","range":60},{"type":"language","mode":"fixed","language":"comun"},{"type":"language","mode":"fixed","language":"dwarfico"},{"type":"resistance","damageType":"poison"},{"type":"note","text":"You have advantage on saving throws against poison."},{"type":"note","text":"Whenever you make an Intelligence (History) check related to the origin of stonework, you are considered proficient in the History skill and add double your proficiency bonus."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'mediano', 'Mediano', 'Especie pequena y resolutiva, marcada por su suerte, agilidad y valentia inesperada.', 'Entrada canonica ampliada para incorporar una especie pequena del SRD con rasgos sociales y defensivos distintivos.', 'small', 25, array['comun', 'halfling']::text[], array['lightfoot-halfling', 'stout-halfling']::text[], '[{"type":"ability_bonus","ability":"dexterity","value":2},{"type":"speed","value":25},{"type":"language","mode":"fixed","language":"comun"},{"type":"language","mode":"fixed","language":"halfling"},{"type":"note","text":"When you roll a 1 on the d20 for an attack roll, ability check, or saving throw, you can reroll the die and must use the new roll."},{"type":"note","text":"You have advantage on saving throws against being frightened."},{"type":"note","text":"You can move through the space of any creature that is of a size larger than yours."}]'::jsonb, true)
insert into subspecies (owner_user_id, source_id, visibility, species_slug, slug, name, summary, description, mechanics, is_system_content)
values
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'elfo', 'high-elf', 'High Elf', 'Subespecie elfica con entrenamiento adicional y aptitud magica.', 'Seed inicial para validar la relacion species-subspecies dentro del catalogo. El contenido detallado puede ampliarse mas adelante.', '[{"type":"ability_bonus","ability":"intelligence","value":1},{"type":"proficiency","proficiencyType":"weapon","value":"longsword"},{"type":"proficiency","proficiencyType":"weapon","value":"shortsword"},{"type":"proficiency","proficiencyType":"weapon","value":"shortbow"},{"type":"proficiency","proficiencyType":"weapon","value":"longbow"},{"type":"choose_language","count":1},{"type":"note","text":"Gain one wizard cantrip of your choice."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'elfo', 'wood-elf', 'Wood Elf', 'Subespecie elfica agil y sigilosa, adaptada a territorios salvajes.', 'Seed inicial para ampliar la cobertura del catalogo species-subspecies con una variante orientada a movilidad y exploracion.', '[{"type":"ability_bonus","ability":"wisdom","value":1},{"type":"speed","value":35},{"type":"note","text":"You can attempt to hide even when you are only lightly obscured by foliage, heavy rain, falling snow, mist, and other natural phenomena."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'enano', 'hill-dwarf', 'Hill Dwarf', 'Subespecie enana perseverante, sabia y especialmente resistente a la fatiga.', 'Entrada canonica ampliada para reforzar la rama de enanos con una opcion orientada a aguante y tradicion.', '[{"type":"ability_bonus","ability":"wisdom","value":1},{"type":"note","text":"Your hit point maximum increases by 1, and it increases by 1 every time you gain a level."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'enano', 'mountain-dwarf', 'Mountain Dwarf', 'Subespecie enana de complexon poderosa, entrenada para la guerra y el uso de armaduras.', 'Entrada canonica ampliada para reforzar la cobertura marcial del creador guiado con una variante enana robusta.', '[{"type":"ability_bonus","ability":"strength","value":2},{"type":"proficiency","proficiencyType":"armor","value":"light-armor"},{"type":"proficiency","proficiencyType":"armor","value":"medium-armor"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'mediano', 'lightfoot-halfling', 'Lightfoot Halfling', 'Subespecie mediana afable y discreta, con talento natural para pasar desapercibida.', 'Entrada canonica ampliada para cubrir una variante social y sigilosa de los medianos.', '[{"type":"ability_bonus","ability":"charisma","value":1},{"type":"note","text":"You can attempt to hide even when you are obscured only by a creature that is at least one size larger than you."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'mediano', 'stout-halfling', 'Stout Halfling', 'Subespecie mediana resistente y sobria, notable por su aguante frente a toxinas.', 'Entrada canonica ampliada para cubrir una variante mediana defensiva con resistencia adicional.', '[{"type":"ability_bonus","ability":"constitution","value":1},{"type":"resistance","damageType":"poison"},{"type":"note","text":"You have advantage on saving throws against poison."}]'::jsonb, true)
insert into character_classes (owner_user_id, source_id, visibility, slug, name, hit_die, primary_abilities, saving_throw_proficiencies, armor_proficiencies, weapon_proficiencies, tool_proficiencies, skill_choices, starting_equipment, spellcasting_ability, progression, summary, description, mechanics, is_system_content)
values
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'guerrero', 'Guerrero', 10, array['strength', 'dexterity']::text[], array['strength', 'constitution']::text[], array['all-armor', 'shields']::text[], array['simple-weapons', 'martial-weapons']::text[], '{}'::text[], '{"count":2,"options":["acrobatics","animal-handling","athletics","history","insight","intimidation","perception","survival"]}'::jsonb, '[{"type":"item","id":"chain-mail"},{"type":"choice","options":["martial-weapon-and-shield","two-martial-weapons"]},{"type":"choice","options":["light-crossbow-and-20-bolts","two-handaxes"]},{"type":"choice","options":["dungeoneers-pack","explorers-pack"]}]'::jsonb, null, '[{"level":1,"features":["fighting-style","second-wind"]}]'::jsonb, 'Clase marcial versatil enfocada en armas, armaduras y resistencia.', 'Seed inicial basada en la documentacion SRD del proyecto. Conviene contrastar la redaccion final con la fuente oficial antes de poblar mas niveles y opciones.', '[{"type":"proficiency","proficiencyType":"armor","value":"all-armor"},{"type":"proficiency","proficiencyType":"armor","value":"shields"},{"type":"proficiency","proficiencyType":"weapon","value":"simple-weapons"},{"type":"proficiency","proficiencyType":"weapon","value":"martial-weapons"},{"type":"proficiency","proficiencyType":"saving_throw","value":"strength"},{"type":"proficiency","proficiencyType":"saving_throw","value":"constitution"},{"type":"choose_proficiency","proficiencyType":"skill","count":2,"options":["acrobatics","animal-handling","athletics","history","insight","intimidation","perception","survival"]},{"type":"feature","featureId":"fighting-style"},{"type":"feature","featureId":"second-wind"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'clerigo', 'Clerigo', 8, array['wisdom']::text[], array['wisdom', 'charisma']::text[], array['light-armor', 'medium-armor', 'shields']::text[], array['simple-weapons']::text[], '{}'::text[], '{"count":2,"options":["history","insight","medicine","persuasion","religion"]}'::jsonb, '[{"type":"choice","options":["mace","warhammer"],"note":"Warhammer requires martial weapon proficiency."},{"type":"choice","options":["scale-mail","leather-armor","chain-mail"],"note":"Chain mail requires proficiency."},{"type":"choice","options":["light-crossbow-and-20-bolts","any-simple-weapon"]},{"type":"choice","options":["priests-pack","explorers-pack"]},{"type":"item","id":"shield"},{"type":"item","id":"holy-symbol"}]'::jsonb, 'wisdom', '[{"level":1,"features":["spellcasting","divine-domain"]},{"level":2,"features":["channel-divinity","divine-domain-feature"]}]'::jsonb, 'Clase divina que combina magia de apoyo, curacion y presencia marcial basica.', 'Seed inicial basada en reglas basicas oficiales. La preparacion completa de conjuros y dominios se modelara de forma incremental.', '[{"type":"proficiency","proficiencyType":"armor","value":"light-armor"},{"type":"proficiency","proficiencyType":"armor","value":"medium-armor"},{"type":"proficiency","proficiencyType":"armor","value":"shields"},{"type":"proficiency","proficiencyType":"weapon","value":"simple-weapons"},{"type":"proficiency","proficiencyType":"saving_throw","value":"wisdom"},{"type":"proficiency","proficiencyType":"saving_throw","value":"charisma"},{"type":"choose_proficiency","proficiencyType":"skill","count":2,"options":["history","insight","medicine","persuasion","religion"]},{"type":"spellcasting","ability":"wisdom"},{"type":"feature","featureId":"spellcasting"},{"type":"feature","featureId":"divine-domain"},{"type":"feature","featureId":"channel-divinity"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'mago', 'Mago', 6, array['intelligence']::text[], array['intelligence', 'wisdom']::text[], '{}'::text[], array['dagger', 'dart', 'sling', 'quarterstaff', 'light-crossbow']::text[], '{}'::text[], '{"count":2,"options":["arcana","history","insight","investigation","medicine","religion"]}'::jsonb, '[{"type":"choice","options":["quarterstaff","any-simple-weapon"]},{"type":"item","id":"spellbook"},{"type":"choice","options":["explorers-pack","dungeoneers-pack"]},{"type":"item","id":"satchel"}]'::jsonb, 'intelligence', '[{"level":1,"features":["spellcasting","arcane-recovery"]},{"level":2,"features":["arcane-tradition"]}]'::jsonb, 'Clase arcana centrada en estudio, preparacion y control flexible del repertorio de conjuros.', 'Seed inicial basada en reglas basicas oficiales. La progresion completa del grimorio y las escuelas se ampliara de forma incremental.', '[{"type":"proficiency","proficiencyType":"weapon","value":"dagger"},{"type":"proficiency","proficiencyType":"weapon","value":"dart"},{"type":"proficiency","proficiencyType":"weapon","value":"sling"},{"type":"proficiency","proficiencyType":"weapon","value":"quarterstaff"},{"type":"proficiency","proficiencyType":"weapon","value":"light-crossbow"},{"type":"proficiency","proficiencyType":"saving_throw","value":"intelligence"},{"type":"proficiency","proficiencyType":"saving_throw","value":"wisdom"},{"type":"choose_proficiency","proficiencyType":"skill","count":2,"options":["arcana","history","insight","investigation","medicine","religion"]},{"type":"spellcasting","ability":"intelligence"},{"type":"feature","featureId":"spellcasting"},{"type":"feature","featureId":"arcane-recovery"},{"type":"feature","featureId":"arcane-tradition"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'picaro', 'Picaro', 8, array['dexterity']::text[], array['dexterity', 'intelligence']::text[], array['light-armor']::text[], array['simple-weapons', 'hand-crossbow', 'longsword', 'rapier', 'shortsword']::text[], array['thieves-tools']::text[], '{"count":4,"options":["acrobatics","athletics","deception","insight","intimidation","investigation","perception","performance","persuasion","sleight-of-hand","stealth"]}'::jsonb, '[{"type":"choice","options":["rapier","shortsword"]},{"type":"choice","options":["shortbow-and-20-arrows","shortsword"]},{"type":"choice","options":["burglars-pack","dungeoneers-pack","explorers-pack"]},{"type":"item","id":"leather-armor"},{"type":"item","id":"dagger","quantity":2},{"type":"item","id":"thieves-tools"}]'::jsonb, null, '[{"level":1,"features":["expertise","sneak-attack","thieves-cant"]},{"level":2,"features":["cunning-action"]},{"level":3,"features":["roguish-archetype"]}]'::jsonb, 'Clase agil y oportunista, experta en sigilo, precision y habilidades utilitarias.', 'Entrada canonica ampliada para cubrir una clase de nivel 1 muy relevante para el creador guiado y con elecciones claras de equipo y habilidades.', '[{"type":"proficiency","proficiencyType":"armor","value":"light-armor"},{"type":"proficiency","proficiencyType":"weapon","value":"simple-weapons"},{"type":"proficiency","proficiencyType":"weapon","value":"hand-crossbow"},{"type":"proficiency","proficiencyType":"weapon","value":"longsword"},{"type":"proficiency","proficiencyType":"weapon","value":"rapier"},{"type":"proficiency","proficiencyType":"weapon","value":"shortsword"},{"type":"proficiency","proficiencyType":"tool","value":"thieves-tools"},{"type":"proficiency","proficiencyType":"saving_throw","value":"dexterity"},{"type":"proficiency","proficiencyType":"saving_throw","value":"intelligence"},{"type":"choose_proficiency","proficiencyType":"skill","count":4,"options":["acrobatics","athletics","deception","insight","intimidation","investigation","perception","performance","persuasion","sleight-of-hand","stealth"]},{"type":"feature","featureId":"expertise"},{"type":"feature","featureId":"sneak-attack"},{"type":"feature","featureId":"thieves-cant"},{"type":"feature","featureId":"cunning-action"},{"type":"feature","featureId":"roguish-archetype"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'barbaro', 'Barbaro', 12, array['strength', 'constitution']::text[], array['strength', 'constitution']::text[], array['light-armor', 'medium-armor', 'shields']::text[], array['simple-weapons', 'martial-weapons']::text[], '{}'::text[], '{"count":2,"options":["animal-handling","athletics","intimidation","nature","perception","survival"]}'::jsonb, '[{"type":"choice","options":["greataxe","martial-melee-weapon"]},{"type":"choice","options":["two-handaxes","any-simple-weapon"]},{"type":"item","id":"explorers-pack"},{"type":"item","id":"four-javelins"}]'::jsonb, null, '[{"level":1,"features":["rage","unarmored-defense"]},{"level":2,"features":["reckless-attack","danger-sense"]},{"level":3,"features":["primal-path"]}]'::jsonb, 'Clase marcial feroz basada en resistencia fisica, furia y asaltos contundentes.', 'Entrada canonica ampliada para cubrir una clase base del SRD centrada en supervivencia y combate directo sin dependencia de conjuros.', '[{"type":"proficiency","proficiencyType":"armor","value":"light-armor"},{"type":"proficiency","proficiencyType":"armor","value":"medium-armor"},{"type":"proficiency","proficiencyType":"armor","value":"shields"},{"type":"proficiency","proficiencyType":"weapon","value":"simple-weapons"},{"type":"proficiency","proficiencyType":"weapon","value":"martial-weapons"},{"type":"proficiency","proficiencyType":"saving_throw","value":"strength"},{"type":"proficiency","proficiencyType":"saving_throw","value":"constitution"},{"type":"choose_proficiency","proficiencyType":"skill","count":2,"options":["animal-handling","athletics","intimidation","nature","perception","survival"]},{"type":"feature","featureId":"rage"},{"type":"feature","featureId":"unarmored-defense"},{"type":"feature","featureId":"reckless-attack"},{"type":"feature","featureId":"danger-sense"},{"type":"feature","featureId":"primal-path"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'monje', 'Monje', 8, array['dexterity', 'wisdom']::text[], array['strength', 'dexterity']::text[], '{}'::text[], array['simple-weapons', 'shortsword']::text[], '{}'::text[], '{"count":2,"options":["acrobatics","athletics","history","insight","religion","stealth"]}'::jsonb, '[{"type":"choice","options":["shortsword","any-simple-weapon"]},{"type":"choice","options":["dungeoneers-pack","explorers-pack"]},{"type":"item","id":"ten-darts"}]'::jsonb, null, '[{"level":1,"features":["unarmored-defense","martial-arts"]},{"level":2,"features":["ki","unarmored-movement"]},{"level":3,"features":["monastic-tradition","deflect-missiles"]}]'::jsonb, 'Clase disciplinada y veloz que combina tecnica marcial, movilidad y control del cuerpo.', 'Entrada canonica ampliada para cubrir una clase base del SRD con progresion temprana clara y sin dependencia fuerte de conjuros.', '[{"type":"proficiency","proficiencyType":"weapon","value":"simple-weapons"},{"type":"proficiency","proficiencyType":"weapon","value":"shortsword"},{"type":"proficiency","proficiencyType":"saving_throw","value":"strength"},{"type":"proficiency","proficiencyType":"saving_throw","value":"dexterity"},{"type":"choose_proficiency","proficiencyType":"skill","count":2,"options":["acrobatics","athletics","history","insight","religion","stealth"]},{"type":"feature","featureId":"unarmored-defense"},{"type":"feature","featureId":"martial-arts"},{"type":"feature","featureId":"ki"},{"type":"feature","featureId":"unarmored-movement"},{"type":"feature","featureId":"monastic-tradition"},{"type":"feature","featureId":"deflect-missiles"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'bardo', 'Bardo', 8, array['charisma']::text[], array['dexterity', 'charisma']::text[], array['light-armor']::text[], array['simple-weapons', 'hand-crossbow', 'longsword', 'rapier', 'shortsword']::text[], array['musical-instrument']::text[], '{"count":3,"options":["acrobatics","animal-handling","arcana","athletics","deception","history","insight","intimidation","investigation","medicine","nature","perception","performance","persuasion","religion","sleight-of-hand","stealth","survival"]}'::jsonb, '[{"type":"choice","options":["rapier","shortsword","any-simple-weapon"]},{"type":"choice","options":["diplomats-pack","entertainers-pack"]},{"type":"choice","options":["lute","musical-instrument"]},{"type":"item","id":"leather-armor"},{"type":"item","id":"dagger"}]'::jsonb, 'charisma', '[{"level":1,"features":["spellcasting","bardic-inspiration"]},{"level":2,"features":["jack-of-all-trades","song-of-rest"]},{"level":3,"features":["bard-college","expertise"]}]'::jsonb, 'Clase carismatica y versatil que mezcla inspiracion, conocimiento y magia de apoyo.', 'Entrada canonica ampliada para abrir una rama lanzadora del SRD apoyada en el catalogo de conjuros ya disponible.', '[{"type":"proficiency","proficiencyType":"armor","value":"light-armor"},{"type":"proficiency","proficiencyType":"weapon","value":"simple-weapons"},{"type":"proficiency","proficiencyType":"weapon","value":"hand-crossbow"},{"type":"proficiency","proficiencyType":"weapon","value":"longsword"},{"type":"proficiency","proficiencyType":"weapon","value":"rapier"},{"type":"proficiency","proficiencyType":"weapon","value":"shortsword"},{"type":"proficiency","proficiencyType":"tool","value":"musical-instrument"},{"type":"proficiency","proficiencyType":"saving_throw","value":"dexterity"},{"type":"proficiency","proficiencyType":"saving_throw","value":"charisma"},{"type":"choose_proficiency","proficiencyType":"skill","count":3,"options":["acrobatics","animal-handling","arcana","athletics","deception","history","insight","intimidation","investigation","medicine","nature","perception","performance","persuasion","religion","sleight-of-hand","stealth","survival"]},{"type":"spellcasting","ability":"charisma"},{"type":"feature","featureId":"spellcasting"},{"type":"feature","featureId":"bardic-inspiration"},{"type":"feature","featureId":"jack-of-all-trades"},{"type":"feature","featureId":"song-of-rest"},{"type":"feature","featureId":"bard-college"},{"type":"feature","featureId":"expertise"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'druida', 'Druida', 8, array['wisdom']::text[], array['intelligence', 'wisdom']::text[], array['light-armor', 'medium-armor', 'shields']::text[], array['club', 'dagger', 'dart', 'javelin', 'mace', 'quarterstaff', 'scimitar', 'sickle', 'sling', 'spear']::text[], array['herbalism-kit']::text[], '{"count":2,"options":["arcana","animal-handling","insight","medicine","nature","perception","religion","survival"]}'::jsonb, '[{"type":"choice","options":["shield","any-simple-weapon"]},{"type":"choice","options":["scimitar","any-simple-weapon"]},{"type":"item","id":"leather-armor"},{"type":"item","id":"explorers-pack"},{"type":"item","id":"druidic-focus"}]'::jsonb, 'wisdom', '[{"level":1,"features":["druidic","spellcasting"]},{"level":2,"features":["wild-shape","druid-circle"]},{"level":3,"features":["circle-spells"]}]'::jsonb, 'Clase sabia y versatil que canaliza la magia de la naturaleza, la curacion y la transformacion.', 'Entrada canonica ampliada para abrir una rama naturalista del SRD con identidad magica propia y progresion clara desde nivel 1.', '[{"type":"proficiency","proficiencyType":"armor","value":"light-armor"},{"type":"proficiency","proficiencyType":"armor","value":"medium-armor"},{"type":"proficiency","proficiencyType":"armor","value":"shields"},{"type":"proficiency","proficiencyType":"weapon","value":"club"},{"type":"proficiency","proficiencyType":"weapon","value":"dagger"},{"type":"proficiency","proficiencyType":"weapon","value":"dart"},{"type":"proficiency","proficiencyType":"weapon","value":"javelin"},{"type":"proficiency","proficiencyType":"weapon","value":"mace"},{"type":"proficiency","proficiencyType":"weapon","value":"quarterstaff"},{"type":"proficiency","proficiencyType":"weapon","value":"scimitar"},{"type":"proficiency","proficiencyType":"weapon","value":"sickle"},{"type":"proficiency","proficiencyType":"weapon","value":"sling"},{"type":"proficiency","proficiencyType":"weapon","value":"spear"},{"type":"proficiency","proficiencyType":"tool","value":"herbalism-kit"},{"type":"proficiency","proficiencyType":"saving_throw","value":"intelligence"},{"type":"proficiency","proficiencyType":"saving_throw","value":"wisdom"},{"type":"choose_proficiency","proficiencyType":"skill","count":2,"options":["arcana","animal-handling","insight","medicine","nature","perception","religion","survival"]},{"type":"language","mode":"fixed","language":"druidico"},{"type":"spellcasting","ability":"wisdom"},{"type":"feature","featureId":"druidic"},{"type":"feature","featureId":"spellcasting"},{"type":"feature","featureId":"wild-shape"},{"type":"feature","featureId":"druid-circle"},{"type":"feature","featureId":"circle-spells"}]'::jsonb, true)
insert into subclasses (owner_user_id, source_id, visibility, class_slug, slug, name, summary, description, granted_spells_by_level, features, mechanics, is_system_content)
values
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'clerigo', 'life-domain', 'Life Domain', 'Dominio clerical centrado en curacion, vitalidad y proteccion de la vida.', 'Seed inicial derivado de reglas basicas oficiales. Mantener la redaccion mecanica breve y ampliar solo tras validar el modelo del catalogo.', '[{"level":1,"spellSlugs":["bless","cure-wounds"]},{"level":3,"spellSlugs":["lesser-restoration","spiritual-weapon"]},{"level":5,"spellSlugs":["beacon-of-hope","revivify"]},{"level":7,"spellSlugs":["death-ward","guardian-of-faith"]},{"level":9,"spellSlugs":["mass-cure-wounds","raise-dead"]}]'::jsonb, '[{"level":1,"featureId":"bonus-proficiency","name":"Bonus Proficiency","summary":"Ganas competencia con armadura pesada.","mechanics":[{"type":"proficiency","proficiencyType":"armor","value":"heavy-armor"}]},{"level":1,"featureId":"disciple-of-life","name":"Disciple of Life","summary":"Tus conjuros de curacion recuperan puntos de golpe adicionales.","mechanics":[{"type":"note","text":"When you use a spell of 1st level or higher to restore hit points, add 2 + the spell level."}]},{"level":2,"featureId":"preserve-life","name":"Channel Divinity: Preserve Life","summary":"Canalizas energia curativa para repartir puntos de golpe entre criaturas cercanas.","mechanics":[{"type":"note","text":"Restore hit points equal to five times your cleric level, divided among creatures within 30 feet, up to half their maximum hit points."}]}]'::jsonb, '[{"type":"spell_grant","spellId":"bless"},{"type":"spell_grant","spellId":"cure-wounds"},{"type":"spell_grant","spellId":"lesser-restoration"},{"type":"spell_grant","spellId":"spiritual-weapon"},{"type":"spell_grant","spellId":"beacon-of-hope"},{"type":"spell_grant","spellId":"revivify"},{"type":"spell_grant","spellId":"death-ward"},{"type":"spell_grant","spellId":"guardian-of-faith"},{"type":"spell_grant","spellId":"mass-cure-wounds"},{"type":"spell_grant","spellId":"raise-dead"},{"type":"proficiency","proficiencyType":"armor","value":"heavy-armor"},{"type":"feature","featureId":"bonus-proficiency"},{"type":"feature","featureId":"disciple-of-life"},{"type":"feature","featureId":"preserve-life"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'mago', 'school-of-evocation', 'School of Evocation', 'Escuela arcana enfocada en modelar energia destructiva sin perder control tactico.', 'Seed inicial derivado de reglas basicas oficiales. Mantener el detalle mecanico breve hasta ampliar la cobertura de escuelas y rasgos de clase.', '[]'::jsonb, '[{"level":2,"featureId":"evocation-savant","name":"Evocation Savant","summary":"Copias conjuros de evocacion en tu grimorio con menos tiempo y coste.","mechanics":[{"type":"note","text":"The gold and time you must spend to copy an evocation spell into your spellbook is halved."}]},{"level":2,"featureId":"sculpt-spells","name":"Sculpt Spells","summary":"Proteges a aliados elegidos del pleno impacto de tus conjuros de evocacion.","mechanics":[{"type":"note","text":"When you cast an evocation spell that affects other creatures you can see, choose creatures equal to 1 + the spell''s level to automatically succeed on their saving throws and take no damage on a successful save."}]}]'::jsonb, '[{"type":"feature","featureId":"evocation-savant"},{"type":"feature","featureId":"sculpt-spells"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'clerigo', 'knowledge-domain', 'Knowledge Domain', 'Dominio clerical enfocado en aprendizaje sagrado, memoria y acceso a saberes ocultos.', 'Seed inicial derivado de reglas basicas oficiales. Esta entrada amplia la cobertura de conjuros concedidos por subclase y mantiene los rasgos resumidos hasta completar mas niveles.', '[{"level":1,"spellSlugs":["command","identify"]},{"level":3,"spellSlugs":["augury","suggestion"]},{"level":5,"spellSlugs":["nondetection","speak-with-dead"]},{"level":7,"spellSlugs":["arcane-eye","confusion"]},{"level":9,"spellSlugs":["legend-lore","scrying"]}]'::jsonb, '[{"level":1,"featureId":"blessings-of-knowledge","name":"Blessings of Knowledge","summary":"Aprendes idiomas adicionales y ganas una pericia orientada al conocimiento.","mechanics":[{"type":"note","text":"You learn two languages of your choice and become proficient in two of Arcana, History, Nature, or Religion."}]},{"level":2,"featureId":"knowledge-of-the-ages","name":"Channel Divinity: Knowledge of the Ages","summary":"Invocas comprension divina para dominar temporalmente una habilidad o herramienta.","mechanics":[{"type":"note","text":"As an action, choose one skill or tool; for 10 minutes, you have proficiency with the chosen skill or tool."}]},{"level":6,"featureId":"read-thoughts","name":"Channel Divinity: Read Thoughts","summary":"Percibes pensamientos superficiales y puedes dirigir la mente de un objetivo con magia.","mechanics":[{"type":"note","text":"You can read a creature''s surface thoughts and may cast Suggestion on it without expending a spell slot."}]}]'::jsonb, '[{"type":"spell_grant","spellId":"command"},{"type":"spell_grant","spellId":"identify"},{"type":"spell_grant","spellId":"augury"},{"type":"spell_grant","spellId":"suggestion"},{"type":"spell_grant","spellId":"nondetection"},{"type":"spell_grant","spellId":"speak-with-dead"},{"type":"spell_grant","spellId":"arcane-eye"},{"type":"spell_grant","spellId":"confusion"},{"type":"spell_grant","spellId":"legend-lore"},{"type":"spell_grant","spellId":"scrying"},{"type":"feature","featureId":"blessings-of-knowledge"},{"type":"feature","featureId":"knowledge-of-the-ages"},{"type":"feature","featureId":"read-thoughts"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'guerrero', 'champion', 'Champion', 'Arquetipo marcial enfocado en precision atletica, resistencia y excelencia fisica.', 'Seed inicial derivado de reglas basicas oficiales. Esta entrada amplia la cobertura de subclases no lanzadoras de conjuros con rasgos marciales sencillos.', '[]'::jsonb, '[{"level":3,"featureId":"improved-critical","name":"Improved Critical","summary":"Tus golpes arma consiguen impactos criticos con mayor frecuencia.","mechanics":[{"type":"note","text":"Your weapon attacks score a critical hit on a roll of 19 or 20."}]},{"level":7,"featureId":"remarkable-athlete","name":"Remarkable Athlete","summary":"Tu destreza fisica mejora saltos, empujes y pruebas atleticas no dominadas.","mechanics":[{"type":"note","text":"Add half your proficiency bonus to Strength, Dexterity, and Constitution checks you are not already proficient in, and increase your running long jump distance."}]},{"level":10,"featureId":"additional-fighting-style","name":"Additional Fighting Style","summary":"Adoptas un segundo estilo de combate para reforzar tu especializacion marcial.","mechanics":[{"type":"note","text":"You can choose a second option from the Fighting Style class feature."}]}]'::jsonb, '[{"type":"feature","featureId":"improved-critical"},{"type":"feature","featureId":"remarkable-athlete"},{"type":"feature","featureId":"additional-fighting-style"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'picaro', 'thief', 'Thief', 'Arquetipo de picaro centrado en manos rapidas, movilidad y dominio de la infiltracion.', 'Entrada canonica ampliada para dar cobertura a una subclase clasica del SRD sin dependencias de conjuros.', '[]'::jsonb, '[{"level":3,"featureId":"fast-hands","name":"Fast Hands","summary":"Aprovechas tu accion adicional para tareas de manos rapidas y juego sucio utilitario.","mechanics":[{"type":"note","text":"You can use the bonus action granted by Cunning Action to make a Dexterity (Sleight of Hand) check, use thieves'' tools to disarm a trap or open a lock, or take the Use an Object action."}]},{"level":3,"featureId":"second-story-work","name":"Second-Story Work","summary":"Escalas y saltas con soltura poco comun entre aventureros.","mechanics":[{"type":"note","text":"Climbing no longer costs you extra movement, and your running jump distance increases by a number of feet equal to your Dexterity modifier."}]},{"level":9,"featureId":"supreme-sneak","name":"Supreme Sneak","summary":"Tu sigilo mejora notablemente cuando avanzas con cautela.","mechanics":[{"type":"note","text":"You have advantage on a Dexterity (Stealth) check if you move no more than half your speed on the same turn."}]},{"level":13,"featureId":"use-magic-device","name":"Use Magic Device","summary":"Improvisas con objetos magicos incluso cuando normalmente no serias apto para usarlos.","mechanics":[{"type":"note","text":"You ignore all class, race, and level requirements on the use of magic items."}]},{"level":17,"featureId":"thiefs-reflexes","name":"Thief''s Reflexes","summary":"Actuas con una rapidez excepcional al inicio del combate.","mechanics":[{"type":"note","text":"You can take two turns during the first round of any combat, taking your first turn at your normal initiative and your second turn at your initiative minus 10."}]}]'::jsonb, '[{"type":"feature","featureId":"fast-hands"},{"type":"feature","featureId":"second-story-work"},{"type":"feature","featureId":"supreme-sneak"},{"type":"feature","featureId":"use-magic-device"},{"type":"feature","featureId":"thiefs-reflexes"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'barbaro', 'berserker', 'Berserker', 'Camino barbaro orientado a una furia desatada que sacrifica control por agresion implacable.', 'Entrada canonica ampliada para dar cobertura a una subclase barbarica basica del SRD sin mecanicas de lanzamiento de conjuros.', '[]'::jsonb, '[{"level":3,"featureId":"frenzy","name":"Frenzy","summary":"Tu rabia puede convertirse en un estado aun mas feroz a cambio de agotamiento posterior.","mechanics":[{"type":"note","text":"While raging, you can choose to frenzy; if you do, you can make a single melee weapon attack as a bonus action on each of your turns after this one, and you suffer one level of exhaustion when your rage ends."}]},{"level":6,"featureId":"mindless-rage","name":"Mindless Rage","summary":"Tu furia te blinda frente a ciertos efectos mentales mientras permanece activa.","mechanics":[{"type":"note","text":"You can''t be charmed or frightened while raging; if you are charmed or frightened when you enter your rage, the effect is suspended for the duration of the rage."}]},{"level":10,"featureId":"intimidating-presence","name":"Intimidating Presence","summary":"Tu sola presencia puede quebrar la voluntad de un enemigo cercano.","mechanics":[{"type":"note","text":"As an action, choose one creature within 30 feet that can see or hear you; it must succeed on a Wisdom saving throw or be frightened of you until the end of your next turn."}]},{"level":14,"featureId":"retaliation","name":"Retaliation","summary":"Respondes de inmediato a quienes se atreven a herirte en combate cercano.","mechanics":[{"type":"note","text":"When you take damage from a creature within 5 feet of you, you can use your reaction to make a melee weapon attack against that creature."}]}]'::jsonb, '[{"type":"feature","featureId":"frenzy"},{"type":"feature","featureId":"mindless-rage"},{"type":"feature","featureId":"intimidating-presence"},{"type":"feature","featureId":"retaliation"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'monje', 'way-of-the-open-hand', 'Way of the Open Hand', 'Tradicion monastica centrada en dominio corporal, tecnicas precisas y control del campo cuerpo a cuerpo.', 'Entrada canonica ampliada para cubrir una subclase clasica del monje en el SRD sin depender de catalogo adicional de conjuros.', '[]'::jsonb, '[{"level":3,"featureId":"open-hand-technique","name":"Open Hand Technique","summary":"Tus rafagas de golpes pueden derribar, apartar o inutilizar reacciones enemigas.","mechanics":[{"type":"note","text":"Whenever you hit a creature with one of the attacks granted by Flurry of Blows, you can impose one of three effects: knock it prone, push it up to 15 feet away, or prevent it from taking reactions until the end of your next turn."}]},{"level":6,"featureId":"wholeness-of-body","name":"Wholeness of Body","summary":"Canalizas energia interior para restaurar tu propia vitalidad.","mechanics":[{"type":"note","text":"As an action, you regain hit points equal to three times your monk level; you must finish a long rest before using this feature again."}]},{"level":11,"featureId":"tranquility","name":"Tranquility","summary":"Tu serenidad te envuelve en una proteccion sobrenatural al comenzar el dia.","mechanics":[{"type":"note","text":"At the end of a long rest, you gain the effect of a Sanctuary spell that lasts until your next long rest, until you attack, or until you force a creature to make a saving throw."}]},{"level":17,"featureId":"quivering-palm","name":"Quivering Palm","summary":"Implantas vibraciones letales que puedes detonar despues con una simple decision.","mechanics":[{"type":"note","text":"After striking a creature, you can spend ki to set up lethal vibrations that can later force the creature to drop to 0 hit points or take massive necrotic damage on a failed Constitution saving throw."}]}]'::jsonb, '[{"type":"feature","featureId":"open-hand-technique"},{"type":"feature","featureId":"wholeness-of-body"},{"type":"feature","featureId":"tranquility"},{"type":"feature","featureId":"quivering-palm"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'bardo', 'college-of-lore', 'College of Lore', 'Colegio bardico orientado a conocimiento, agudeza verbal y dominio de historias y secretos.', 'Entrada canonica ampliada para cubrir una subclase bardica clasica del SRD con fuerte identidad no dependiente de grants automaticos de conjuros.', '[]'::jsonb, '[{"level":3,"featureId":"bonus-proficiencies","name":"Bonus Proficiencies","summary":"Amplias tu repertorio con nuevas competencias tomadas de cualquier disciplina.","mechanics":[{"type":"note","text":"You gain proficiency with any three skills of your choice."}]},{"level":3,"featureId":"cutting-words","name":"Cutting Words","summary":"Tus pullas y observaciones mordaces pueden debilitar la precision o el aplomo de un enemigo.","mechanics":[{"type":"note","text":"When a creature you can see within 60 feet makes an attack roll, ability check, or damage roll, you can use your reaction to expend a Bardic Inspiration die and subtract the result."}]},{"level":6,"featureId":"additional-magical-secrets","name":"Additional Magical Secrets","summary":"Accedes antes que otros bardos a conjuros ajenos a tu lista habitual.","mechanics":[{"type":"note","text":"You learn two spells of your choice from any class, counting them as bard spells for you."}]},{"level":14,"featureId":"peerless-skill","name":"Peerless Skill","summary":"Tu inspiracion puede perfeccionar incluso tus propias hazanas con maestria sobresaliente.","mechanics":[{"type":"note","text":"When you make an ability check, you can expend one use of Bardic Inspiration to add the Bardic Inspiration die to your roll."}]}]'::jsonb, '[{"type":"choose_proficiency","proficiencyType":"skill","count":3,"options":["acrobatics","animal-handling","arcana","athletics","deception","history","insight","intimidation","investigation","medicine","nature","perception","performance","persuasion","religion","sleight-of-hand","stealth","survival"]},{"type":"feature","featureId":"bonus-proficiencies"},{"type":"feature","featureId":"cutting-words"},{"type":"feature","featureId":"additional-magical-secrets"},{"type":"feature","featureId":"peerless-skill"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'druida', 'circle-of-the-land', 'Circle of the Land', 'Circulo druídico orientado a la profundidad espiritual, la recuperación mágica y la sintonía con biomas concretos.', 'Entrada canonica ampliada para cubrir una subclase druídica clásica del SRD con soporte inicial de conjuros de círculo.', '[{"level":3,"spellSlugs":["invisibility","spider-climb"]},{"level":5,"spellSlugs":["call-lightning","sleet-storm"]},{"level":7,"spellSlugs":["divination","freedom-of-movement"]},{"level":9,"spellSlugs":["dream","insect-plague"]}]'::jsonb, '[{"level":2,"featureId":"bonus-cantrip","name":"Bonus Cantrip","summary":"Tu vínculo con la tierra te concede un truco druídico adicional.","mechanics":[{"type":"note","text":"You learn one additional druid cantrip of your choice."}]},{"level":2,"featureId":"natural-recovery","name":"Natural Recovery","summary":"Recuperas parte de tu poder mágico durante una pausa breve en la naturaleza.","mechanics":[{"type":"note","text":"During a short rest, you can recover expended spell slots with a combined level equal to or less than half your druid level, rounded up."}]},{"level":10,"featureId":"natures-ward","name":"Nature''s Ward","summary":"La naturaleza te protege frente a encantamientos y criaturas feéricas o elementales.","mechanics":[{"type":"note","text":"You can''t be charmed or frightened by elementals or fey, and you are immune to poison and disease."}]},{"level":14,"featureId":"natures-sanctuary","name":"Nature''s Sanctuary","summary":"Las bestias y seres vegetales sienten tu autoridad natural y dudan antes de atacarte.","mechanics":[{"type":"note","text":"Beasts and plants must make a Wisdom saving throw before choosing you as a target for an attack or harmful spell."}]}]'::jsonb, '[{"type":"spell_grant","spellId":"invisibility"},{"type":"spell_grant","spellId":"spider-climb"},{"type":"spell_grant","spellId":"call-lightning"},{"type":"spell_grant","spellId":"sleet-storm"},{"type":"spell_grant","spellId":"divination"},{"type":"spell_grant","spellId":"freedom-of-movement"},{"type":"spell_grant","spellId":"dream"},{"type":"spell_grant","spellId":"insect-plague"},{"type":"feature","featureId":"bonus-cantrip"},{"type":"feature","featureId":"natural-recovery"},{"type":"feature","featureId":"natures-ward"},{"type":"feature","featureId":"natures-sanctuary"}]'::jsonb, true)
insert into backgrounds (owner_user_id, source_id, visibility, slug, name, skill_proficiencies, tool_proficiencies, languages, equipment, feature_name, summary, description, mechanics, is_system_content)
values
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'acolyte', 'Acolyte', array['insight', 'religion']::text[], '{}'::text[], array['choose:any:2']::text[], '[{"type":"item","id":"holy-symbol"},{"type":"choice","options":["prayer-book","prayer-wheel"]},{"type":"item","id":"sticks-of-incense","quantity":5},{"type":"item","id":"vestments"},{"type":"item","id":"common-clothes"},{"type":"item","id":"belt-pouch","note":"Contains 15 gp."}]'::jsonb, 'Shelter of the Faithful', 'Trasfondo religioso centrado en estudio, rituales y apoyo de una comunidad de fe.', 'Seed inicial del SRD para disponer de un trasfondo reutilizable en formularios y futuras pantallas de contenido.', '[{"type":"proficiency","proficiencyType":"skill","value":"insight"},{"type":"proficiency","proficiencyType":"skill","value":"religion"},{"type":"choose_language","count":2},{"type":"note","text":"Can receive healing and care at temples that share your faith, and may call on priests for modest assistance."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'soldier', 'Soldier', array['athletics', 'intimidation']::text[], array['gaming-set', 'vehicles-land']::text[], '{}'::text[], '[{"type":"item","id":"insignia-of-rank"},{"type":"item","id":"trophy-from-a-fallen-enemy"},{"type":"choice","options":["bone-dice","cards"]},{"type":"item","id":"common-clothes"},{"type":"item","id":"belt-pouch","note":"Contains 10 gp."}]'::jsonb, 'Military Rank', 'Trasfondo marcial que aporta disciplina, experiencia militar y reconocimiento entre tropas.', 'Seed inicial del SRD para representar competencias y rasgos sociales reutilizables.', '[{"type":"proficiency","proficiencyType":"skill","value":"athletics"},{"type":"proficiency","proficiencyType":"skill","value":"intimidation"},{"type":"proficiency","proficiencyType":"tool","value":"gaming-set"},{"type":"proficiency","proficiencyType":"tool","value":"vehicles-land"},{"type":"note","text":"Soldiers loyal to your former military organization still recognize your authority and influence."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'criminal', 'Criminal', array['deception', 'stealth']::text[], array['thieves-tools', 'gaming-set']::text[], '{}'::text[], '[{"type":"item","id":"crowbar"},{"type":"item","id":"dark-common-clothes"},{"type":"item","id":"belt-pouch","note":"Contains 15 gp."}]'::jsonb, 'Criminal Contact', 'Trasfondo urbano y clandestino que aporta engaño, sigilo y contactos dentro del hampa.', 'Entrada canonica ampliada para cubrir uno de los trasfondos mas utiles del SRD en combinacion con personajes orientados a sigilo.', '[{"type":"proficiency","proficiencyType":"skill","value":"deception"},{"type":"proficiency","proficiencyType":"skill","value":"stealth"},{"type":"proficiency","proficiencyType":"tool","value":"thieves-tools"},{"type":"proficiency","proficiencyType":"tool","value":"gaming-set"},{"type":"note","text":"You have a reliable and trustworthy contact who acts as your liaison to a network of other criminals."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'noble', 'Noble', array['history', 'persuasion']::text[], array['gaming-set']::text[], array['choose:any:1']::text[], '[{"type":"item","id":"fine-clothes"},{"type":"item","id":"signet-ring"},{"type":"item","id":"parchment-scroll"},{"type":"item","id":"belt-pouch","note":"Contains 25 gp."}]'::jsonb, 'Position of Privilege', 'Trasfondo social de alta cuna que aporta educacion, influencia y reconocimiento cortesano.', 'Entrada canonica ampliada para cubrir un trasfondo de interaccion social fuerte dentro del SRD.', '[{"type":"proficiency","proficiencyType":"skill","value":"history"},{"type":"proficiency","proficiencyType":"skill","value":"persuasion"},{"type":"proficiency","proficiencyType":"tool","value":"gaming-set"},{"type":"choose_language","count":1},{"type":"note","text":"People are inclined to think the best of you, and common folk make every effort to accommodate you and avoid your displeasure."}]'::jsonb, true)
insert into spells (owner_user_id, source_id, visibility, slug, name, level, school, casting_time, range_text, components, materials, duration, concentration, ritual, class_slugs, summary, description, mechanics, is_system_content)
values
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'guidance', 'Guidance', 0, 'divination', '1 action', 'Touch', 'V, S', null, 'Concentration, up to 1 minute', true, false, array['clerigo', 'druida']::text[], 'Una criatura suma 1d4 a una prueba de caracteristica antes de que termine el conjuro.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'friends', 'Friends', 0, 'enchantment', '1 action', 'Self', 'S, M', 'A bit of makeup applied to the face as this spell is cast.', 'Concentration, up to 1 minute', true, false, array['bardo']::text[], 'Obtienes ventaja social frente a una criatura no hostil, aunque despues sabra que la influiste magicamente.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'druidcraft', 'Druidcraft', 0, 'transmutation', '1 action', '30 feet', 'V, S', null, 'Instantaneous', false, false, array['druida']::text[], 'Invocas pequeños prodigios naturales como prever el tiempo, hacer brotar flores o encender semillas.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'light', 'Light', 0, 'evocation', '1 action', 'Touch', 'V, M', 'A firefly or phosphorescent moss.', '1 hour', false, false, array['bardo', 'mago']::text[], 'Un objeto tocado emite luz brillante y tenue durante una hora.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'minor-illusion', 'Minor Illusion', 0, 'illusion', '1 action', '30 feet', 'S, M', 'A bit of fleece.', '1 minute', false, false, array['bardo', 'mago']::text[], 'Creas un sonido o una imagen estatica sencilla para distraer, ocultar o engañar.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'mage-hand', 'Mage Hand', 0, 'conjuration', '1 action', '30 feet', 'V, S', null, '1 minute', false, false, array['bardo', 'mago']::text[], 'Creas una mano espectral para manipular objetos a distancia.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'ray-of-frost', 'Ray of Frost', 0, 'evocation', '1 action', '60 feet', 'V, S', null, 'Instantaneous', false, false, array['druida', 'mago']::text[], 'Un rayo helado inflige dano por frio y reduce la velocidad del objetivo.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'resistance', 'Resistance', 0, 'abjuration', '1 action', 'Touch', 'V, S, M', 'A miniature cloak.', 'Concentration, up to 1 minute', true, false, array['bardo', 'clerigo']::text[], 'Una criatura tocada suma 1d4 a una tirada de salvacion antes de que el conjuro termine.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'sacred-flame', 'Sacred Flame', 0, 'evocation', '1 action', '60 feet', 'V, S', null, 'Instantaneous', false, false, array['bardo', 'clerigo']::text[], 'Una llama radiante obliga a una salvacion de destreza e inflige dano radiante.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'spare-the-dying', 'Spare the Dying', 0, 'necromancy', '1 action', 'Touch', 'V, S', null, 'Instantaneous', false, false, array['clerigo', 'druida']::text[], 'Una criatura moribunda se estabiliza sin recuperar puntos de golpe.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'shocking-grasp', 'Shocking Grasp', 0, 'evocation', '1 action', 'Touch', 'V, S', null, 'Instantaneous', false, false, array['bardo', 'mago']::text[], 'Una descarga electrica hiere al objetivo e impide que use reacciones hasta su siguiente turno.', null, '[]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'prestidigitation', 'Prestidigitation', 0, 'transmutation', '1 action', '10 feet', 'V, S', null, 'Up to 1 hour', false, false, array['bardo', 'mago']::text[], 'Realizas pequenos trucos magicos de utilidad, limpieza, distraccion o adorno arcano.', null, '[]'::jsonb, true),
